/// uexp/ubulk constants for T_Bkg textures.
///
/// Ported verbatim from RR_VHS_Tool.py:1068-1086.
/// All offsets and sizes are universal for 1024×2048 DXT1 T_Bkg textures.
/// Do not change without a parity test — every byte here was derived by
/// inspection of the base game's binary uassets.
library;

import 'dart:typed_data';

import 'genres.dart';

/// Ubulk size for a single base T_Bkg texture: only mip 0 (1024×2048 DXT1).
/// Formula: (W/4) * (H/4) * 8.  RR_VHS_Tool.py:5590.
const int kBkgUbulkSize = (kTextureBkgWidth ~/ 4) * (kTextureBkgHeight ~/ 4) * 8;
// = 1,048,576

/// Ubulk size used for *all* injected T_Bkg / T_New textures: 5 external mips.
/// RR_VHS_Tool.py:5591-5594.
///
/// The template uexp (`kTBkgUexpTemplate`) declares 5 external mips, so even
/// a plain T_Bkg replacement writes a 5-mip ubulk to satisfy the template.
const int kTNewUbulkSize = 1396736;
// = sum((W>>m)/4 * (H>>m)/4 * 8 for m in 0..4)
// = 1,048,576 + 262,144 + 65,536 + 16,384 + 4,096 = 1,396,736

/// Offsets and sizes of inline mip pixel data inside the 1702-byte
/// `kTBkgUexpTemplate`.  Mips 0-4 live in the external ubulk; mips 5-11
/// are inline in the uexp at these offsets.  RR_VHS_Tool.py:1077-1086.
///
/// (mipLevel, uexpOffset, pixelDataSize)
const List<(int, int, int)> kUexpInlineMipMap = [
  (5, 0x00C2, 1024), //  32x64
  (6, 0x04D2, 256), //   16x32
  (7, 0x05E2, 64), //    8x16
  (8, 0x0632, 16), //    4x8
  (9, 0x0652, 8), //     2x4
  (10, 0x066A, 8), //    1x2
  (11, 0x0682, 8), //    1x1
];

/// 1702-byte uexp template for a fresh T_Bkg texture entry.
/// Used as the fallback when the base game uexp can't be extracted (e.g.
/// because the source slot doesn't exist in the base pak yet).
/// RR_VHS_Tool.py:1068-1071.
final Uint8List kTBkgUexpTemplate = _hexToBytes(_kTBkgUexpTemplateHex);

const String _kTBkgUexpTemplateHex =
    '';

Uint8List _hexToBytes(String hex) {
  if (hex.length.isOdd) {
    throw ArgumentError('hex string length must be even, got ${hex.length}');
  }
  final out = Uint8List(hex.length ~/ 2);
  for (var i = 0; i < out.length; i++) {
    out[i] = int.parse(hex.substring(i * 2, i * 2 + 2), radix: 16);
  }
  return out;
}
